children.value:
var(--a00000000000)
				color-mix(in hsl, var(--b1000000, var(--b2000000)) var(--b3000000), transparent),
			var(--c00000000000) color-mix(in hsl, var(--d1000000) var(--d2000000), transparent)

content.styles:
div {
	/* Each comma item has space-separated values; first item exceeds width, second fits */
	--shadow1:
		var(--a00000000000)
			color-mix(in hsl, var(--b1000000, var(--b2000000)) var(--b3000000), transparent),
		var(--c00000000000) color-mix(in hsl, var(--d1000000) var(--d2000000), transparent);
}
